mapper.select:
select saai.id as rowId,saai.apply_name as applyName,saai.award_name as awardName, csal.name as awardLevelName, saai.start_date as startDate, saai.end_date as endDate,saai.note, cspais.name as stateName from srm_award_apply_info saai left join ct_srm_award_level csal on csal.code=saai.award_level left join ct_srm_project_apply_info_state cspais on cspais.code=saai.state where 1=1
and saai.apply_name=#{awardApplyInfoDto.applyName}
order by saai.id desc
